@@ -484,7 +484,10 @@
-        // Normalize empty components to ""
-        String s;
-        var auth  = (s = u.getAuthority()) == null || s.isEmpty() ? "" : s;
-        var path  = (s = u.getPath())  == null ? "" : s;
-        var query = (s = u.getQuery()) == null ? "" : s;
-        var ref   = (s = u.getRef())   == null ? "" : s;
-
+        // Optimizations in this method are based on the following observations:
+        // 1: The query and ref components are commonly empty and can be specialized
+        // 2: String concatenation is faster when locals are concatenated with no interleaving code
+        // 3: A single concatenation is faster than combining results of other concatenations
+
+        // Optionality, subtly different for authority
+        var emptyAuth = u.getAuthority() == null || u.getAuthority().isEmpty();
+        var emptyPath = u.getPath() == null;
+        var emptyQuery = u.getQuery() == null;
+        var emptyRef = u.getRef() == null;
@@ -492,6 +495,5 @@
-        if (query == "" && ref == "") {
-            if (auth == "") {
-                return u.getProtocol() + ":" + path;
-            } else {
-                return u.getProtocol() + "://" + auth + path;
-            }
+        if (emptyQuery && emptyRef) {
+            var path = emptyPath ? "" : u.getPath();
+            return emptyAuth
+                    ? (u.getProtocol() + ":" + path)
+                    : (u.getProtocol() + "://" + u.getAuthority() + path);
@@ -499,7 +501,10 @@
-
-        // General case
-        var aSep = auth  != "" ? "//" : "";
-        var qSep = query != "" ? "?"  : "";
-        var rSep = ref   != "" ? "#"  : "";
-        return u.getProtocol() + ":"
-                + aSep + auth
+        // Prefer locals for efficient concatenation
+        var authSep = emptyAuth ? ":" : "://";
+        var auth = emptyAuth ? "" : u.getAuthority();
+        var path = emptyPath ? "" : u.getPath();
+        var querySep = emptyQuery ? "" : "?";
+        var query = emptyQuery ? "" : u.getQuery();
+        var refSep = emptyRef ? "" : "#";
+        var ref = emptyRef ? "" : u.getRef();
+        return u.getProtocol()
+                + authSep + auth
@@ -507,2 +512,2 @@
-                + qSep + query
-                + rSep + ref;
+                + querySep + query
+                + refSep + ref;
